package main

import (
	"context"
	"flag"
	"fmt"
	"log/slog"
	"os"
	"os/signal"
	"strings"
	"syscall"

	"github.com/ketang/kapow/tools/kapow/internal/config"
	"github.com/ketang/kapow/tools/kapow/internal/dbutil"
	"github.com/ketang/kapow/tools/kapow/internal/fetch"
)

func main() {
	if len(os.Args) < 2 {
		printUsage()
		os.Exit(1)
	}

	cmd := os.Args[1]

	// Handle help and sources before flag parsing.
	switch cmd {
	case "-h", "--help", "help":
		printUsage()
		return
	case "sources":
		printSources()
		return
	}

	cfg := &config.Config{}

	// Check for a registered importer first.
	if imp := Get(cmd); imp != nil {
		fs := flag.NewFlagSet(cmd, flag.ExitOnError)
		cfg.RegisterFlags(fs)
		imp.RegisterFlags(fs)
		if err := fs.Parse(os.Args[2:]); err != nil {
			fmt.Fprintf(os.Stderr, "error: %v\n", err)
			os.Exit(1)
		}

		setupLogging(cfg)
		if err := runImporter(imp, cfg); err != nil {
			slog.Error("import failed", "importer", cmd, "error", err)
			os.Exit(1)
		}
		return
	}

	// Built-in commands.
	switch cmd {
	case "run-all":
		fs := flag.NewFlagSet("run-all", flag.ExitOnError)
		cfg.RegisterFlags(fs)
		skipFlag := fs.String("skip", "", "comma-separated importers to skip")
		onlyFlag := fs.String("only", "", "comma-separated importers to run (exclusive)")
		if err := fs.Parse(os.Args[2:]); err != nil {
			fmt.Fprintf(os.Stderr, "error: %v\n", err)
			os.Exit(1)
		}

		setupLogging(cfg)

		skip := parseCSV(*skipFlag)
		only := parseCSV(*onlyFlag)

		if err := runAll(cfg, skip, only); err != nil {
			slog.Error("run-all failed", "error", err)
			os.Exit(1)
		}
	default:
		fmt.Fprintf(os.Stderr, "unknown command: %s\n\n", cmd)
		printUsage()
		os.Exit(1)
	}
}

func runImporter(imp Importer, cfg *config.Config) error {
	ctx, cancel := signal.NotifyContext(context.Background(), syscall.SIGINT, syscall.SIGTERM)
	defer cancel()

	if cfg.DryRun {
		slog.Info("dry-run mode enabled — no database writes")
		fetcher := fetch.New(cfg.CacheDir)
		return imp.Run(ctx, cfg, nil, fetcher)
	}

	if cfg.DatabaseURL == "" {
		return fmt.Errorf("kapow: DATABASE_URL is required (set via --database-url or env)")
	}

	pool, err := dbutil.Connect(ctx, cfg.DatabaseURL)
	if err != nil {
		return err
	}
	defer pool.Close()

	fetcher := fetch.New(cfg.CacheDir)
	return imp.Run(ctx, cfg, pool, fetcher)
}

func runAll(cfg *config.Config, skip, only map[string]bool) error {
	ctx, cancel := signal.NotifyContext(context.Background(), syscall.SIGINT, syscall.SIGTERM)
	defer cancel()

	if cfg.DatabaseURL == "" {
		return fmt.Errorf("kapow: DATABASE_URL is required")
	}

	pool, err := dbutil.Connect(ctx, cfg.DatabaseURL)
	if err != nil {
		return err
	}
	defer pool.Close()

	fetcher := fetch.New(cfg.CacheDir)

	if err := RunAll(ctx, cfg, pool, fetcher, skip, only); err != nil {
		return err
	}

	slog.Info("refreshing materialized views")
	return dbutil.RefreshMaterializedViews(ctx, pool)
}

func setupLogging(cfg *config.Config) {
	level := cfg.SlogLevel()
	handler := slog.NewTextHandler(os.Stderr, &slog.HandlerOptions{Level: level})
	slog.SetDefault(slog.New(handler))
}

func parseCSV(s string) map[string]bool {
	m := make(map[string]bool)
	if s == "" {
		return m
	}
	for _, v := range strings.Split(s, ",") {
		v = strings.TrimSpace(v)
		if v != "" {
			m[v] = true
		}
	}
	return m
}

func printUsage() {
	fmt.Fprintf(os.Stderr, `kapow — Kapow data pipeline tool

Usage: kapow <command> [flags]

Commands:
  fetch <source>   Download and archive data from a source
  fetch all        Download everything
  import <source>  Import from archive into DB
  import all       Import all in dependency order
  run-all          Fetch all + import all in dependency order
  sources          Print data source documentation

Available sources:
`)
	for _, imp := range registry {
		fmt.Fprintf(os.Stderr, "  %-16s %s\n", imp.Name(), imp.Description())
	}
	fmt.Fprintf(os.Stderr, `
Global flags:
  --database-url   PostgreSQL DSN (default: $DATABASE_URL)
  --cache-dir      Download cache dir (default: ~/.cache/kapow)
  --log-level      debug|info|warn|error (default: info)
  --dry-run        Parse and validate without writing to DB
`)
}

func printSources() {
	fmt.Println("See DATA_SOURCES.md in this directory for complete data source documentation.")
}

